export interface ThumbnailPrompt {
  id: string;
  conceptName: string;
  visualDescription: string;
  textOverlay: string;
  compositionNotes: string;
  psychologicalTrigger: string;
  ctrRating: number;
  tags: string[];
  createdAt: string;
}

export interface TrendData {
  topic: string;
  momentum: 'rising' | 'peaked' | 'fading';
  visualStyle: string;
  sourceUrl: string;
}

export interface AppState {
  history: ThumbnailPrompt[];
  knowledgeBase: string[];
  currentNiche: string;
  branding: {
    name: string;
    colors: string[];
    vibe: string;
  };
}

export enum View {
  DASHBOARD = 'DASHBOARD',
  GENERATOR = 'GENERATOR',
  DISCOVERY = 'DISCOVERY',
  LEARNING = 'LEARNING'
}

import { GoogleGenAI, Type } from "@google/genai";
import { ThumbnailPrompt, TrendData } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const THUMBNAIL_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    conceptName: { type: Type.STRING },
    visualDescription: { type: Type.STRING, description: "Detailed AI image generation prompt for the background and main subjects." },
    textOverlay: { type: Type.STRING, description: "Highly legible text to be placed on the thumbnail." },
    compositionNotes: { type: Type.STRING, description: "Notes on framing, lighting, and focal points for mobile visibility." },
    psychologicalTrigger: { type: Type.STRING, description: "The specific emotion or curiosity gap being exploited." },
    ctrRating: { type: Type.NUMBER, description: "Estimated click potential from 1-100." },
    tags: { type: Type.ARRAY, items: { type: Type.STRING } }
  },
  required: ["conceptName", "visualDescription", "textOverlay", "compositionNotes", "psychologicalTrigger", "ctrRating", "tags"]
};

export const generateThumbnailPrompts = async (
  title: string, 
  niche: string, 
  audience: string, 
  context: string[] = []
): Promise<ThumbnailPrompt[]> => {
  const systemInstruction = `
    You are a world-class YouTube Thumbnail Strategist for @iconicbeatsla.
    Your mission is to generate 3 distinct thumbnail concepts that are "SEO Primed" and engineered for viral CTR.

    BRANDING GUIDELINES (@iconicbeatsla):
    - Aesthetic: High-end music production, sleek, urban, "Iconic" vibes.
    - Colors: Electric Blue, Deep Purple, Gold, Matte Black.
    - Visibility: Must be legible on 4-inch mobile screens. Use high contrast and massive typography.

    PSYCHOLOGICAL TRIGGERS:
    - Curiosity gaps, "The Secret," Unexpected results, Extreme emotion, "Wait for it."

    EVOLUTIONARY CONTEXT:
    ${context.length > 0 ? "Past successful strategies to adapt from: " + context.join(". ") : "No previous data yet. Use standard viral patterns."}
  `;

  const prompt = `Create 3 SEO-primed thumbnail concepts for a video titled: "${title}" in the ${niche} niche, targeting ${audience}.`;

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: THUMBNAIL_SCHEMA
      }
    }
  });

  try {
    const data = JSON.parse(response.text || "[]") as any[];
    return data.map((item, idx) => ({
      ...item,
      id: Math.random().toString(36).substr(2, 9),
      createdAt: new Date().toISOString()
    }));
  } catch (e) {
    console.error("Failed to parse Gemini response", e);
    return [];
  }
};

export const researchTrends = async (niche: string): Promise<TrendData[]> => {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `What are the currently trending YouTube thumbnail visual styles and topics in the ${niche} niche? Focus on what is working RIGHT NOW.`,
    config: {
      tools: [{ googleSearch: {} }]
    }
  });

  const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
  const text = response.text || "";

  // We'll use another pass to structure this into a clean list for the UI
  const structuredResponse = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Based on this research: "${text}", extract a list of 5 trending topics and styles.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            topic: { type: Type.STRING },
            momentum: { type: Type.STRING, enum: ['rising', 'peaked', 'fading'] },
            visualStyle: { type: Type.STRING },
            sourceUrl: { type: Type.STRING }
          },
          required: ["topic", "momentum", "visualStyle"]
        }
      }
    }
  });

  try {
    return JSON.parse(structuredResponse.text || "[]");
  } catch (e) {
    return [];
  }
};

import React, { useState, useEffect } from 'react';
import { View, AppState, ThumbnailPrompt } from './types';
import Dashboard from './components/Dashboard';
import PromptGenerator from './components/PromptGenerator';
import DiscoveryLab from './components/DiscoveryLab';
import LearningCenter from './components/LearningCenter';
import { Layout } from './components/Layout';

const STORAGE_KEY = 'iconic_click_state';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>(View.DASHBOARD);
  const [state, setState] = useState<AppState>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) return JSON.parse(saved);
    return {
      history: [],
      knowledgeBase: [
        "Use high contrast for @iconicbeatsla branding",
        "Curiosity gaps drive the most clicks",
        "Large faces with extreme expressions perform well"
      ],
      currentNiche: "Music Production",
      branding: {
        name: "@iconicbeatsla",
        colors: ["#3b82f6", "#8b5cf6", "#ffd700", "#000000"],
        vibe: "Iconic, Sleek, High-Energy"
      }
    };
  });

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  }, [state]);

  const addPromptToHistory = (prompts: ThumbnailPrompt[]) => {
    setState(prev => ({
      ...prev,
      history: [...prompts, ...prev.history].slice(0, 50)
    }));
  };

  const updateKnowledgeBase = (insight: string) => {
    setState(prev => ({
      ...prev,
      knowledgeBase: [insight, ...prev.knowledgeBase].slice(0, 20)
    }));
  };

  const renderView = () => {
    switch (currentView) {
      case View.DASHBOARD:
        return <Dashboard state={state} onNavigate={setCurrentView} />;
      case View.GENERATOR:
        return <PromptGenerator 
          state={state} 
          onPromptsGenerated={addPromptToHistory} 
        />;
      case View.DISCOVERY:
        return <DiscoveryLab state={state} onLearn={updateKnowledgeBase} />;
      case View.LEARNING:
        return <LearningCenter state={state} onUpdateState={setState} />;
      default:
        return <Dashboard state={state} onNavigate={setCurrentView} />;
    }
  };

  return (
    <Layout currentView={currentView} onNavigate={setCurrentView}>
      {renderView()}
    </Layout>
  );
};

export default App;

