import React, { useState } from 'react';
import { AppState, ThumbnailPrompt } from '../types';
import { generateThumbnailPrompts } from '../services/geminiService';

interface PromptGeneratorProps {
  state: AppState;
  onPromptsGenerated: (prompts: ThumbnailPrompt[]) => void;
}

const PromptGenerator: React.FC<PromptGeneratorProps> = ({ state, onPromptsGenerated }) => {
  const [loading, setLoading] = useState(false);
  const [results, setResults] = useState<ThumbnailPrompt[]>([]);
  const [formData, setFormData] = useState({
    title: '',
    niche: state.currentNiche,
    audience: 'Music Producers & Creatives'
  });

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.title) return;

    setLoading(true);
    setResults([]);
    try {
      const data = await generateThumbnailPrompts(
        formData.title,
        formData.niche,
        formData.audience,
        state.knowledgeBase
      );
      setResults(data);
      onPromptsGenerated(data);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto space-y-12">
      {/* Input Section */}
      <section className="bg-white/5 border border-white/10 p-8 rounded-3xl shadow-2xl relative overflow-hidden">
        <div className="absolute top-0 right-0 p-4 opacity-10">
          <svg className="w-32 h-32" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
        </div>

        <h2 className="text-2xl font-black mb-6 flex items-center gap-2">
          <span className="w-2 h-8 bg-blue-500 rounded-full"></span>
          Engine Input
        </h2>

        <form onSubmit={handleGenerate} className="space-y-6">
          <div className="space-y-2">
            <label className="text-xs font-bold uppercase tracking-widest text-white/50">Primary Video Title</label>
            <input 
              type="text"
              required
              placeholder="e.g., How I Made a Chart-Topping Beat in 10 Minutes"
              className="w-full bg-black/50 border border-white/10 rounded-xl px-5 py-4 text-lg focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all"
              value={formData.title}
              onChange={(e) => setFormData({...formData, title: e.target.value})}
            />
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-2">
              <label className="text-xs font-bold uppercase tracking-widest text-white/50">Market Niche</label>
              <select 
                className="w-full bg-black/50 border border-white/10 rounded-xl px-5 py-4 focus:outline-none focus:ring-2 focus:ring-blue-500 appearance-none"
                value={formData.niche}
                onChange={(e) => setFormData({...formData, niche: e.target.value})}
              >
                <option>Music Production</option>
                <option>Tech & Gadgets</option>
                <option>Lifestyle & Luxury</option>
                <option>Tutorials & Education</option>
                <option>Gaming & Entertainment</option>
              </select>
            </div>
            <div className="space-y-2">
              <label className="text-xs font-bold uppercase tracking-widest text-white/50">Target Audience Profile</label>
              <input 
                type="text"
                placeholder="e.g., Aspiring musicians, 18-35"
                className="w-full bg-black/50 border border-white/10 rounded-xl px-5 py-4 focus:outline-none focus:ring-2 focus:ring-blue-500"
                value={formData.audience}
                onChange={(e) => setFormData({...formData, audience: e.target.value})}
              />
            </div>
          </div>

          <button 
            type="submit"
            disabled={loading}
            className={`w-full py-5 rounded-2xl font-black text-xl uppercase tracking-widest transition-all ${
              loading 
                ? 'bg-blue-600/50 cursor-not-allowed' 
                : 'bg-gradient-to-r from-blue-600 to-purple-600 hover:scale-[1.02] active:scale-95 shadow-xl shadow-blue-500/20'
            }`}
          >
            {loading ? (
              <span className="flex items-center justify-center gap-3">
                <svg className="animate-spin h-5 w-5 text-white" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                Processing Bio-Data...
              </span>
            ) : "Ignite Strategic Engine"}
          </button>
        </form>
      </section>

      {/* Results Section */}
      {results.length > 0 && (
        <section className="space-y-8 animate-in fade-in slide-in-from-bottom-8 duration-700">
          <div className="flex items-center justify-between">
