                            className="mt-2 text-blue-400 text-[10px] font-bold uppercase hover:underline block"
                          >Copy to Clipboard</button>
                        </div>
                      </div>
                      <div className="space-y-2">
                        <span className="text-xs font-bold text-white/40 uppercase tracking-widest">Mobile Visibility Composition</span>
                        <p className="text-sm text-white/60 italic leading-relaxed">{item.compositionNotes}</p>
                      </div>
                    </div>

                    <div className="space-y-4 bg-white/5 p-6 rounded-2xl border border-white/5 flex flex-col justify-center items-center text-center">
                      <span className="text-xs font-bold text-white/40 uppercase tracking-widest mb-4">Master Text Overlay</span>
