  const handleResearch = async () => {
    setLoading(true);
    try {
      const data = await researchTrends(state.currentNiche);
      setTrends(data);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleAdopt = (trend: TrendData) => {
    onLearn(`Adopted Trend: ${trend.topic} - Strategy: ${trend.visualStyle}`);
