import React, { useState } from 'react';
import { AppState, TrendData } from '../types';
import { researchTrends } from '../services/geminiService';

interface DiscoveryLabProps {
  state: AppState;
  onLearn: (insight: string) => void;
}

const DiscoveryLab: React.FC<DiscoveryLabProps> = ({ state, onLearn }) => {
  const [loading, setLoading] = useState(false);
  const [trends, setTrends] = useState<TrendData[]>([]);

  const handleResearch = async () => {
    setLoading(true);
    try {
      const data = await researchTrends(state.currentNiche);
      setTrends(data);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleAdopt = (trend: TrendData) => {
    onLearn(`Trend Alert: ${trend.topic} - Visual: ${trend.visualStyle}`);
    alert(`Knowledge Base Updated: ${trend.topic}`);
  };

  return (
    <div className="space-y-12 pb-20 animate-in fade-in duration-500">
      <header className="flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div>
          <h2 className="text-4xl font-black text-white tracking-tight">Trend Discovery Lab</h2>
          <p className="text-white/40 mt-2">Deep-scanning YouTube algorithms for {state.currentNiche} trends...</p>
        </div>
        <button 
          onClick={handleResearch}
          disabled={loading}
          className="bg-purple-600 hover:bg-purple-500 text-white font-black px-8 py-4 rounded-xl transition-all shadow-lg shadow-purple-500/20 flex items-center gap-2 group"
        >
          {loading ? (
            <svg className="animate-spin h-5 w-5 mr-3 text-white" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
          ) : (
            <svg className="w-5 h-5 group-hover:rotate-12 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19.428 15.428a2 2 0 00-1.022-.547l-2.387-.477a6 6 0 00-3.86.517l-.618.309a6 6 0 01-3.86.517l-3.158-.632a2 2 0 01-1.223-1.223L3.5 11.5a2 2 0 011.223-1.223l3.158-.632a6 6 0 013.86.517l.618.309a6 6 0 003.86.517l2.387-.477a2 2 0 001.022-.547l3.5-3.5" /></svg>
          )}
          {loading ? "Decrypting Metadata..." : "Initialize Global Scan"}
        </button>
      </header>

      {trends.length > 0 ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {trends.map((trend, idx) => (
            <div key={idx} className="bg-white/5 border border-white/10 rounded-2xl p-6 flex flex-col hover:border-purple-500/50 transition-all group relative overflow-hidden">
               <div className="absolute top-0 right-0 w-24 h-24 bg-purple-500/5 blur-3xl rounded-full -mr-8 -mt-8"></div>

              <div className="flex items-center justify-between mb-4 relative z-10">
                <span className={`text-[10px] font-bold px-2 py-1 rounded-md uppercase tracking-widest ${
                  trend.momentum === 'rising' ? 'bg-green-500/20 text-green-400' :
                  trend.momentum === 'peaked' ? 'bg-yellow-500/20 text-yellow-400' :
                  'bg-red-500/20 text-red-400'
                }`}>
                  {trend.momentum}
                </span>
                <span className="text-white/20 text-xs font-mono">ID:SCAN_{idx + 101}</span>
              </div>

              <h3 className="text-xl font-bold mb-3 relative z-10">{trend.topic}</h3>
              <p className="text-white/50 text-sm leading-relaxed mb-6 flex-1 italic relative z-10">
                "{trend.visualStyle}"
              </p>

              {trend.sourceUrl && (
                <div className="mb-4">
                  <a 
                    href={trend.sourceUrl} 
                    target="_blank" 
                    rel="noopener noreferrer"
                    className="text-[10px] text-blue-400 hover:underline flex items-center gap-1"
                  >
                    <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14" /></svg>
                    Evidence Source
                  </a>
                </div>
              )}

              <button 
                onClick={() => handleAdopt(trend)}
                className="w-full py-3 bg-white/5 hover:bg-white/10 border border-white/10 rounded-xl text-xs font-bold uppercase tracking-widest transition-all text-white/60 hover:text-white relative z-10"
              >
                Integrate Insight
              </button>
            </div>
          ))}
        </div>
      ) : !loading && (
        <div className="py-32 text-center border-2 border-dashed border-white/5 rounded-3xl">
          <div className="inline-flex items-center justify-center w-20 h-20 bg-white/5 rounded-full mb-6 text-white/20">
             <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
          </div>
          <h3 className="text-xl font-bold text-white/60 uppercase tracking-widest">No Trend Data</h3>
          <p className="text-white/30 text-sm max-w-md mx-auto mt-2">The system is ready for calibration. Perform a global scan to pull real-time data from the SEO matrix.</p>
        </div>
      )}

      {/* Evolutionary Lab Status */}
      <div className="bg-gradient-to-r from-blue-900/10 to-purple-900/10 border border-white/10 p-8 rounded-3xl relative overflow-hidden">
        <div className="absolute top-0 right-0 p-8 opacity-5">
           <svg className="w-48 h-48" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M9.663 17h4.674a1 1 0 00.922-.606l2.024-4.722a1 1 0 00.117-.466V7a2 2 0 00-2-2H4.663a2 2 0 00-2 2v2.206c0 .164.04.325.117.466l2.024 4.722a1 1 0 00.922.606z" /></svg>
        </div>
        <h4 className="text-lg font-bold mb-4 flex items-center gap-2 relative z-10">
          <span className="w-2 h-2 bg-blue-500 rounded-full animate-ping"></span>
          Discovery Hypothesis Engine
        </h4>
        <div className="space-y-4 relative z-10">
          <p className="text-white/60 text-sm leading-relaxed max-w-2xl">
            Our current cross-niche audit reveals a 40% uptick in <span className="text-white font-bold underline decoration-blue-500 underline-offset-4 decoration-2">Lo-Fi Industrial Aesthetics</span>. Users are responding to authentic, non-polished looks that contrast with traditional high-gloss thumbnails. Integrating this into your prompts might trigger immediate curiosity spikes.
          </p>
          <div className="flex gap-4 overflow-x-auto pb-4 scrollbar-hide">
            {["Grunge Overlays", "Grainy Textures", "Handwritten Font", "Realism"].map(tag => (
              <span key={tag} className="shrink-0 px-4 py-2 bg-black/40 border border-white/10 rounded-full text-[10px] font-black uppercase tracking-widest text-white/50">{tag}</span>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default DiscoveryLab;

