export interface ThumbnailPrompt {
  id: string;
  conceptName: string;
  visualDescription: string;
  textOverlay: string;
  compositionNotes: string;
  psychologicalTrigger: string;
  ctrRating: number;
  tags: string[];
  createdAt: string;
}

export interface TrendData {
  topic: string;
  momentum: 'rising' | 'peaked' | 'fading';
  visualStyle: string;
  sourceUrl?: string;
}

export interface AppState {
  history: ThumbnailPrompt[];
  knowledgeBase: string[];
  discoveryHistory: TrendData[];
  currentNiche: string;
  branding: {
    name: string;
    colors: string[];
    vibe: string;
  };
}

export enum View {
  DASHBOARD = 'DASHBOARD',
  GENERATOR = 'GENERATOR',
  DISCOVERY = 'DISCOVERY',
  LEARNING = 'LEARNING',
  STRATEGY = 'STRATEGY'
}

import React, { useState, useEffect } from 'react';
import { View, AppState, ThumbnailPrompt, TrendData } from './types';
import Dashboard from './components/Dashboard';
import PromptGenerator from './components/PromptGenerator';
import DiscoveryLab from './components/DiscoveryLab';
import LearningCenter from './components/LearningCenter';
import StrategyCenter from './components/StrategyCenter';
import { Layout } from './components/Layout';

const STORAGE_KEY = 'iconic_click_state_v2';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>(View.DASHBOARD);
  const [state, setState] = useState<AppState>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) return JSON.parse(saved);
    return {
      history: [],
      knowledgeBase: [
        "Use high contrast for @iconicbeatsla branding",
        "Curiosity gaps drive the most clicks",
        "Large faces with extreme expressions perform well"
      ],
      discoveryHistory: [],
      currentNiche: "Music Production",
      branding: {
        name: "@iconicbeatsla",
        colors: ["#3b82f6", "#8b5cf6", "#ffd700", "#000000"],
        vibe: "Iconic, Sleek, High-Energy"
      }
    };
  });

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  }, [state]);

  const addPromptToHistory = (prompts: ThumbnailPrompt[]) => {
    setState(prev => ({
      ...prev,
      history: [...prompts, ...prev.history].slice(0, 50)
    }));
  };

  const updateKnowledgeBase = (insight: string) => {
    setState(prev => ({
      ...prev,
      knowledgeBase: [insight, ...prev.knowledgeBase].slice(0, 20)
    }));
  };

  const addTrendsToHistory = (trends: TrendData[]) => {
    setState(prev => ({
      ...prev,
      discoveryHistory: [...trends, ...prev.discoveryHistory].slice(0, 30)
    }));
  };

  const renderView = () => {
    switch (currentView) {
      case View.DASHBOARD:
        return <Dashboard state={state} onNavigate={setCurrentView} />;
      case View.GENERATOR:
        return <PromptGenerator 
          state={state} 
          onPromptsGenerated={addPromptToHistory} 
        />;
      case View.DISCOVERY:
        return <DiscoveryLab 
          state={state} 
          onLearn={updateKnowledgeBase} 
          onTrendsFound={addTrendsToHistory}
        />;
      case View.LEARNING:
        return <LearningCenter state={state} onUpdateState={setState} />;
      case View.STRATEGY:
        return <StrategyCenter state={state} />;
      default:
        return <Dashboard state={state} onNavigate={setCurrentView} />;
    }
  };

  return (
    <Layout currentView={currentView} onNavigate={setCurrentView}>
      {renderView()}
    </Layout>
  );
};

export default App;

