interface PromptGeneratorProps {
  state: AppState;
  onPromptsGenerated: (prompts: ThumbnailPrompt[]) => void;
  onToggleSave: (prompt: ThumbnailPrompt) => void;
  onPlatformChange: (platform: Platform) => void;
}

const PromptGenerator: React.FC<PromptGeneratorProps> = ({ state, onPromptsGenerated, onToggleSave, onPlatformChange }) => {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [results, setResults] = useState<ThumbnailPrompt[]>([]);
  const [formData, setFormData] = useState({
    title: '',
    niche: state.currentNiche,
    audience: 'Broad Market Creatives',
    platform: state.currentPlatform
  });

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.title) return;

    setLoading(true);
    setError(null);
    setResults([]);
    try {
      const data = await generateThumbnailPrompts(
        formData.title,
        formData.niche,
        formData.audience,
        formData.platform,
        state.knowledgeBase
      );
      setResults(data);
      onPromptsGenerated(data);
    } catch (err: any) {
      setError(err?.message || "Generation failed");
    } finally {
      setLoading(false);
    }
  };

  const platforms: Platform[] = ['YouTube', 'YouTube Shorts', 'Facebook', 'Instagram', 'X', 'Reddit', 'Pinterest'];

  return (
    <div className="max-w-4xl mx-auto space-y-12 pb-24">
      <section className="bg-white/5 border border-white/10 p-8 rounded-3xl shadow-2xl relative overflow-hidden">
        <h2 className="text-2xl font-black mb-6 flex items-center gap-2">
          <span className="w-2 h-8 bg-blue-500 rounded-full"></span>
          Strategic Engine
        </h2>

        <form onSubmit={handleGenerate} className="space-y-6">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-2">
              <label className="text-xs font-bold uppercase tracking-widest text-white/50">Core Topic / Title</label>
              <input 
                type="text"
                required
