                value={formData.audience}
                onChange={(e) => setFormData({...formData, audience: e.target.value})}
              />
            </div>
          </div>

          <button 
            type="submit"
            disabled={loading}
            className="w-full py-5 bg-gradient-to-r from-blue-600 to-purple-600 rounded-2xl font-black text-xl uppercase shadow-xl hover:scale-[1.01] active:scale-95 transition-all disabled:opacity-50 disabled:cursor-not-allowed"
          >
            {loading ? "Engaging Neural Nexus..." : "Ignite Strategic Engine"}
          </button>
        </form>
      </section>

      {error && <div className="p-4 bg-red-500/20 text-red-400 rounded-xl border border-red-500/30 text-sm">{error}</div>}

      <div className="grid grid-cols-1 gap-8">
        {results.map((item) => (
          <div key={item.id} className="bg-white/5 border-l-4 border-blue-500 rounded-2xl p-8 space-y-6 shadow-xl animate-in fade-in slide-in-from-bottom-4">
