                  <div className="bg-white/5 p-4 rounded-xl flex items-center justify-center text-center h-full min-h-[100px]">
                    <h5 className="text-3xl font-black uppercase tracking-tighter text-transparent bg-clip-text bg-gradient-to-b from-white to-gray-500">
                      {item.textOverlay}
                    </h5>
                  </div>
                </div>
             </div>
             <div className="flex flex-wrap gap-2">
                {item.tags.map(tag => <span key={tag} className="text-[10px] px-2 py-1 bg-white/5 rounded text-white/40 font-mono">#{tag}</span>)}
                <button onClick={() => onToggleSave(item)} className="ml-auto px-4 py-2 bg-blue-600/20 text-blue-400 rounded-lg text-xs font-bold uppercase tracking-widest hover:bg-blue-600 hover:text-white transition-all">
                  {state.savedPrompts.some(p => p.id === item.id) ? "Unsave Asset" : "Save Asset"}
                </button>
             </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default PromptGenerator;

