export const generateImage = async (prompt: string, size: "1K" | "2K" | "4K"): Promise<string> => {
  return callWithRetry(async () => {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: { parts: [{ text: prompt }] },
      config: {
        imageConfig: {
          aspectRatio: "16:9",
          imageSize: size
        }
      },
    });

    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    throw new Error("No image generated");
  });
};

export const editImage = async (base64Image: string, editPrompt: string): Promise<string> => {
  return callWithRetry(async () => {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          { inlineData: { data: base64Image.split(',')[1], mimeType: 'image/png' } },
          { text: editPrompt }
        ]
      }
    });

    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    throw new Error("Image edit failed");
  });
};

export const researchTrends = async (niche: string): Promise<TrendData[]> => {
  return callWithRetry(async () => {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Search for high-performance visual trends and SEO metadata shifts in the ${niche} niche as of today.`,
      config: { tools: [{ googleSearch: {} }] }
    });

    const structuredResponse = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Based on: "${response.text}", extract 5 granular trending patterns.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              topic: { type: Type.STRING },
              momentum: { type: Type.STRING, enum: ['rising', 'peaked', 'fading'] },
              visualStyle: { type: Type.STRING },
